example_1_simple_insertOne.code:
const result = db.students.insertOne({
  studentId: 20260001,
  name: { first: 'Daksh', last: 'Chauhan' },
  age: 20,
  major: 'Data Science',
  gpa: 3.85
});
console.log('Inserted:', result.insertedId);

example_2_simple_insertMany.code:
const students = [
  { studentId: 20260001, name: { first: 'Daksh', last: 'Chauhan' }, ... },
  { studentId: 20260002, name: { first: 'Anaya', last: 'Sharma' }, ... },
  ... (all 60 students)
];
const result = db.students.insertMany(students);
console.log('Inserted ' + result.insertedIds.length + ' students');

example_3_insertMany_with_options.code:
const students = [...data...];
const result = db.students.insertMany(students, { ordered: false });
console.log('Successfully inserted: ' + result.insertedIds.length);
console.log('Total attempted: ' + students.length);

example_4_insertOne_error_handling.code:
try {
  const result = db.students.insertOne(newStudent);
  console.log('Student inserted:', result.insertedId);
} catch (error) {
  if (error.code === 11000) {
    console.log('Duplicate student ID');
  } else {
    console.log('Insert failed:', error.message);
  }
}
